'use client';

import {
    MotionValue,
    useScroll,
    useTransform,
} from 'framer-motion';

type UseParallaxProps = {
    offset?: number;
};

export function useParallax({
    offset = 120,
}: UseParallaxProps = {}): MotionValue<number> {

    const { scrollY } = useScroll();

    return useTransform(
        scrollY,
        [0, 1000],
        [0, offset],
    );
}